INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('second.change','Change','change','Reality_Mechanics/2_Second/Closure Conditions/Change.md','https://atlas.realitymechanics.nz/change.html','# Change

Change names a readable difference across traversal. Where traversal lets a read be followed through a closure scope and difference names readable non-sameness, change names non-sameness becoming readable between one condition and another through traversal.

## Places

Change places a readable difference across traversal.

## Holds

Change is held by [[Traversal]] and [[Difference]].

## Pairs

Asymmetry carries downward. Change is a singular condition through which traversal produces a difference in state. The lateral asymmetry appears in what change carries: [[Growth]] ↔ [[Decay]].

## Traces

- [[Traversal]]
- [[Difference]]

## Nests

Change nests where difference becomes readable across traversal.

## Reads

Change becomes recognisable where a condition can be followed from one readable state to another without losing the path between them.

## Carries

- [[Growth]]
- [[Decay]]
- [[Speed]]
- [[Flow]]
- [[Heat]]
- [[Effect]]
- [[Acceleration]]','Change Change names a readable difference across traversal. Where traversal lets a read be followed through a closure scope and difference names readable non sameness, change names non sameness becoming readable between one condition and another through traversal. Places Change places a readable difference across traversal. Holds Change is held by Traversal and Difference. Pairs Asymmetry carries downward. Change is a singular condition through which traversal produces a difference in state. The lateral asymmetry appears in what change carries: Growth ↔ Decay. Traces Traversal Difference Nests Change nests where difference becomes readable across traversal. Reads Change becomes recognisable where a condition can be followed from one readable state to another without losing the path between them. Carries Growth Decay Speed Flow Heat Effect Acceleration','Change Change names a readable difference across traversal. Where traversal lets a read be followed through a closure scope and difference names readable non sameness, change names non sameness…','stable','rooted',0,'second','term',NULL,'[]','[]','["second.acceleration","second.decay","second.difference","second.effect","second.flow","second.growth","second.heat","second.speed","second.traversal"]','{"holds":["second.traversal","second.difference"],"traces":["second.traversal","second.difference"],"carries":["second.growth","second.decay","second.speed","second.flow","second.heat","second.effect","second.acceleration"],"pairs":["second.growth","second.decay"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',124,'sha256:f02c4ed4dc3cbf760d843951ffae32bdf5865257f54cb057def17b90d14adad0','1970-01-01','2026-06-2