"second.thing"]','{"holds":["first.relation","first.boundary","second.closure-scope","second.scale","second.readability"],"traces":["first.relation","first.boundary","second.closure-scope","second.scale","second.readability"],"carries":["second.thing"],"pairs":[],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',268,'sha256:c391e7276b9919e798182d303bf4a8dbb3bf1e331323e78cf630492a23533e72','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('second.resistance','Resistance','resistance','Reality_Mechanics/2_Second/Carrying Conditions/Resistance.md','https://atlas.realitymechanics.nz/resistance.html','# Resistance

Resistance names carrying opposed, narrowed, or slowed by a condition it must pass through. Failure can follow resistance, but resistance first names the opposition through which carrying changes how it continues.

## Places

Resistance places carrying opposed, narrowed, or slowed by a condition it must pass through.

## Holds

Resistance is held by [[Constraint]], [[Flow]], and [[Carrying]].

## Pairs

Resistance is vertical. It names carrying opposed, narrowed, or slowed by a condition it must pass through, and carries this forward into [[Friction]], [[Drag]], and [[Grip]]. Resistance holds [[Constraint]], [[Flow]], and [[Carrying]] — it is a downstream read of carrying meeting opposition, not a lateral co-present condition alongside another second-order term.

## Traces

- [[Constraint]]
- [[Flow]]
- [[Carrying]]

## Nests

Resistance nests where carrying continues only through opposition, narrowing, or slowing.

## Reads

Resistance becomes recognisable where carrying or flow continues only through opposition, narrowing, or slowing.

## Carries

- [[Friction]]
- [[Drag]]
- [[Grip]]
- [[Contend]]','Resistance Resistance names carrying opposed, narrowed, or slowed by a condition it must pass through. Failure can follow resistance, but resistance first names the opposition through which carrying changes how it continues. Places Resistance places carrying opposed, narrowed, or slowed by a condition it must pass through. Holds Resistance is held by Constraint, Flow, and Carrying. Pairs Resistance is vertical. It names carrying opposed, narrowed, or slowed by a condition it must pass through, and carries this forward into Friction, Drag, and Grip. Resistance holds Constraint, Flow, and Carrying — it is a downstream read of carrying meeting opposition, not a lateral co present condition alongside another second order term. Traces Constraint Flow Carrying Nests Resistance nests where carrying continues only through opposition, narrowing, or slowing. Reads Resistance becomes recognisable where carrying or flow continues only through opposition, narrowing, or slowing. Carries Friction Drag Grip Contend','Resistance Resistance names carrying opposed, narrowed, or slowed by a condition it must pass through. Failure can follow resistance, but resistance first names the opposition through which…','stable','rooted',0,'second','term',NULL,'[]','[]','["practice.contend","second.carrying","second.constraint","second.drag","second.flow","second.friction","second.grip"]','{"holds":["second.constraint","second.flow","second.carrying"],"traces":["second.constraint","second.flow","second.carrying"],"carries":["second.friction","second.drag","second.grip","practice.contend"],"pairs":["second.friction","second.drag","second.grip"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]'