INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.ai-availability','AI Availability','ai-availability','Reality_Mechanics/3_Third/Domains/AI/AI Availability.md','https://atlas.realitymechanics.nz/ai-availability.html','# AI Availability

AI availability names what becomes usable within an AI interaction at the current closure scope.

## Places

AI Availability places the closure-scope condition inside AI interaction — what the current exchange opens as usable without outrunning the participant''s ability to test, carry, or retrace it.

## Holds

AI Availability is held by [[AI]], [[Availability]], and [[Closure Scope]] — it requires that generated possibility remain within the scope the participant can bear and evaluate.

## Pairs

AI Availability pairs with [[AI Atlas Grounding]]. AI Availability names what becomes usable within the coupling; AI Atlas Grounding names the practice that keeps the coupling retraceable. Each is a distinct condition AI Coupling must maintain: usability and retrace-ability.

## Traces

- [[AI]]
- [[Availability]]
- [[Closure Scope]]

## Nests

AI Availability nests within the AI domain as the scope-bounding condition that keeps generated output usable rather than merely received.

## Reads

AI Availability becomes readable where generated possibility becomes usable without outrunning the participant''s ability to test, carry, or retrace it.

## Carries','AI Availability AI availability names what becomes usable within an AI interaction at the current closure scope. Places AI Availability places the closure scope condition inside AI interaction — what the current exchange opens as usable without outrunning the participant''s ability to test, carry, or retrace it. Holds AI Availability is held by AI, Availability, and Closure Scope — it requires that generated possibility remain within the scope the participant can bear and evaluate. Pairs AI Availability pairs with AI Atlas Grounding. AI Availability names what becomes usable within the coupling; AI Atlas Grounding names the practice that keeps the coupling retraceable. Each is a distinct condition AI Coupling must maintain: usability and retrace ability. Traces AI Availability Closure Scope Nests AI Availability nests within the AI domain as the scope bounding condition that keeps generated output usable rather than merely received. Reads AI Availability becomes readable where generated possibility becomes usable without outrunning the participant''s ability to test, carry, or retrace it. Carries','AI Availability AI availability names what becomes usable within an AI interaction at the current closure scope. Places AI Availability places the closure scope condition inside AI interaction —…','stable','rooted',0,'third','term','ai','[]','[]','["first.availability","second.closure-scope","third.ai","third.ai-atlas-grounding"]','{"holds":["third.ai","first.availability","second.closure-scope"],"traces":["third.ai","first.availability","second.closure-scope"],"carries":[],"pairs":["third.ai-atlas-grounding"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',164,'sha256:c43a42deadc8ce2422aae2af8f3955aa164df78d9fafba2548ca8520effd8897','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.ai-confident-correction','AI Confident Correction','ai-confident-correction','Reality_Mechanics/3_Third/Domains/AI/Applied Reads/AI Confident Correction.md','https://atlas.realitymechanics.nz/ai-confident-correction.html','# AI Confident Correction

AI Confident Correction reads a local case where an AI answer appears to repair an error while preserving the wrong grounding.

## Places

AI Confident Correction places the applied read of AI Misrepair — where a correction appears to repair an error while preserving the wrong grounding.

## Holds

AI Confident Correction is held by [[Applied Read]], [[AI Misrepair]], and [[Closure Scope]] — it requires a visible correction event against which misrepair becomes testable.

## Pairs

AI Confident Correction pairs with [[AI Reply Drift]]. Both are applied reads of AI disorder — reply drift at the response level, confident correction at the level of a specific correction event.

## Traces

- [[Applied Read]]
- [[AI Misrepair]]
- [[Closure Scope]]

- [[AI]]
## Nests

AI Confident Correction nests within the AI domain as an applied read of AI Misrepair, scoped to a single correction event.

## Reads

AI Confident Correction becomes readable where a correction preserves interaction while failing to restore the dependency path required by the question.

Case Movement:

```text
error is challenged
-> answer corrects fluently
-> grounding remains wrong
-> correction becomes misrepair
```

