INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.care','Care','care','Reality_Mechanics/3_Third/Fields/Relational Participation/Bearing Relations/Care.md','https://atlas.realitymechanics.nz/care.html','# Care

Care names Bearing preserving Availability through relation. Care remains responsive by attending to the condition whose availability it preserves.

## Places

Care places bearing that preserves availability through relation while remaining attended to the condition whose availability it preserves.

## Holds

Care is held by [[Bearing]], [[Availability]], [[Attend]], [[Kind]], and [[Sustenance]]. Bearing must be present, availability must be at stake, and attention to that availability must be maintained before the condition can be read as care.

## Pairs

Care pairs with [[Control]] and [[Neglect]]. Care names bearing that preserves availability through responsive relation; Control names bearing that directs availability through constraint. Control remains compatible where direction stays answerable to the availability care preserves. Neglect names the failure to hold care''s preserving bearing.

## Traces

- [[Bearing]]
- [[Availability]]
- [[Attend]]
- [[Kind]]
- [[Sustenance]]

## Nests

Care nests within Relational Participation as the condition through which bearing preserves availability in relation — the structural ground for all care-bearing reads.

## Reads

Care becomes readable where bearing preserves availability through relation and remains attended to the condition it is preserving.

Care is band-sensitive. It does not only ask what is good in the abstract; it asks what can be received, integrated, and carried by this participant, body, relation, or field at this resolution band. Too much too fast can become overload. Too little can become neglect. Care preserves availability by matching support to carrying.

## Carries

Care carries [[Neglect]] — the failure to hold the preserving bearing that care requires. Neglect is only readable against the standard care sets.
- [[Neglect]]
- [[Parenting]]
- [[Domination]]
- [[Dominion]]
- [[Tend]]','Care Care names Bearing preserving Availability through relation. Care remains responsive by attending to the condition whose availability it preserves. Places Care places bearing that preserves availability through relation while remaining attended to the condition whose availability it preserves. Holds Care is held by Bearing, Availability, Attend, Kind, and Sustenance. Bearing must be present, availability must be at stake, and attention to that availability must be maintained before the condition can be read as care. Pairs Care pairs with Control and Neglect. Care names bearing that preserves availability through responsive relation; Control names bearing that directs availability through constraint. Control remains compatible where direction stays answerable to the availability care preserves. Neglect names the failure to hold care''s preserving bearing. Traces Bearing Availability Attend Kind Sustenance Nests Care nests within Relational Participation as the condition through which bearing preserves availability in relation — the structural ground for all care bearing reads. Reads Care becomes readable where bearing preserves availability through relation and remains attended to the condition it is preserving. Care is band sensitive. It does not only ask what is good in the abstract; it asks what can be received, integrated, and carried by this participant, body, relation, or field at this resolution band. Too much too fast can become overload. Too little can become neglect. Care preserves availability by matching support to carrying. Carries Care carries Neglect — the failure to hold the preserving bearing that care requires. Neglect is only readable against the standard care sets. Neglect Parenting Domination Dominion Tend','Care Care names Bearing preserving Availability through relation. Care remains responsive by attending to the condition whose availability it preserves.','stable','rooted',0,'third','term','relational-participation','[]','[]','["first.attend","first.availability","first.bearing","practice.tend","second.kind","third.control","third.domination","third.dominion","third.neglect","third.parenting","third.sustenance"]','{"holds":["first.bearing","first.availability","first.attend","second.kind","third.sustenance"],"traces":["first.bearing","first.availability","first.attend","second.kind","third.sustenance"],"carries":["third.neglect","third.parenting","third.domination","third.dominion","practice.tend"],"pairs":["third.control","third.neglect"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',254,'sha256:d053f47b9cbd9fc254ded5bfea4892544b7f9f9ad3d0135e78b3f5c674c8297f','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.caring','Caring','caring','Reality_Mechanics/3_Third/Placement Modes/Caring.md','https://atlas.realitymechanics.nz/caring.html','# Caring

Caring names the placement mode where participation is primarily carried through preserving bearing or availability.

## Places

Caring places the mode where participation is primarily carried through preserving bearing or availability — keeping what must still bear, remain accessible, or be repaired enough to continue.

## Holds

Caring is held by [[Placement Mode]], [[Bearing]], and [[Availability]]. A mode of participation must exist, bearing must be at stake, and availability must be preservable before caring can be placed as the primary mode.

## Pairs

Caring pairs with [[Governing]]. Caring preserves and repairs bearing; Governing directs and constrains it.

## Traces

- [[Placement Mode]]
- [[Bearing]]
- [[Availability]]

## Nests

Caring nests within Placement Modes as the preserving mode — where the primary movement is keeping conditions available for continued bearing rather than directing, transmitting, or transforming them.

## Reads

Caring becomes recognisable where a note is primarily placed by preservation of what must still bear, remain available, or be repaired enough to continue.

## Carries

This note carries no further public branch at this scope.','Caring Caring names the placement mode where participation is primarily carried through preserving bearing or availability. Places Caring places the mode where participation is primarily carried through preserving bearing or availability — keeping what must still bear, remain accessible, or be repaired enough to continue. Holds Caring is held by Placement Mode, Bearing, and Availability. A mode of participation must exist, bearing must be at stake, and availability must be preservable before caring can be placed as the primary mode. Pairs Caring pairs with Governing. Caring preserves and repairs bearing; Governing directs and constrains it. Traces Placement Mode Bearing Availability Nests Caring nests within Placement Modes as the preserving mode — where the primary movement is keeping conditions available for continued bearing rather than directing, transmitting, or transforming them. Reads Caring becomes recognisable where a note is primarily placed by preservation of what must still bear, remain available, or be repaired enough to continue. Carries This note carries no further public branch at this scope.','Caring Caring names the placement mode where participation is primarily carried through preserving bearing or availability. Places Caring places the mode where participation is primarily carried…','stable','rooted',0,'third','term','placement-modes','[]','[]','["first.availability","first.bearing","third.governing","third.placement-mode"]','{"holds":["third.placement-mode","first.bearing","first.availability"],"traces":["third.placement-mode","first.bearing","first.availability"],"carries":[],"pairs":["third.governing"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"