INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.inheritance','Inheritance','inheritance','Reality_Mechanics/3_Third/Fields/Our Story/Inheritance.md','https://atlas.realitymechanics.nz/inheritance.html','# Inheritance

Inheritance names an our-story path read where memory, practice, term, place, obligation, or relation is carried into later participation.

[[Borne and Carried]] names the human-scope condition inside inheritance: human carrying begins in received carrying.

## Places

Inheritance places the condition through which prior carrying is passed forward through recurrence and recognition — what a field, community, or practice continues to carry from prior relation.

## Holds

Inheritance is held by [[Our Story Field]], [[Carrying]], [[Recurrence]], [[Recognition Read|Recognition]], [[Medium]], [[Compatibility]], [[Kind]], and [[Our Story]]. Prior carrying must be present, recurrence must sustain it, and recognition must make it available before forward-passed carrying can be named as inheritance.

## Pairs

Inheritance pairs with [[Carrying Better]]. Inheritance names the forward-passing of prior carrying; Carrying Better names the condition where retrace makes that inheritance correctable.

## Traces

- [[Our Story Field]]
- [[Carrying]]
- [[Recurrence]]
- [[Recognition Read|Recognition]]
- [[Medium]]
- [[Compatibility]]
- [[Kind]]
- [[Our Story]]

## Nests

Inheritance nests within the Our Story Field as the condition through which prior carrying is sustained and passed forward through recognition and recurrence.

## Reads

Inheritance becomes readable where what is received remains identifiable enough to be carried, revised, refused, repaired, or retold.

The dependency movement is:

First: [[Bearing]] and [[Availability]] make something carryable beyond the immediate relation.

Second: [[Carrying]], [[Recurrence]], [[Recognition Read|Recognition]], [[Medium]], and [[Compatibility]] make inheritance evaluable.

Third: [[Inheritance]] places that structural read inside the [[Our Story Field]].

## Carries','Inheritance Inheritance names an our story path read where memory, practice, term, place, obligation, or relation is carried into later participation. Borne and Carried names the human scope condition inside inheritance: human carrying begins in received carrying. Places Inheritance places the condition through which prior carrying is passed forward through recurrence and recognition — what a field, community, or practice continues to carry from prior relation. Holds Inheritance is held by Our Story Field, Carrying, Recurrence, Recognition Read, Medium, Compatibility, Kind, and Our Story. Prior carrying must be present, recurrence must sustain it, and recognition must make it available before forward passed carrying can be named as inheritance. Pairs Inheritance pairs with Carrying Better. Inheritance names the forward passing of prior carrying; Carrying Better names the condition where retrace makes that inheritance correctable. Traces Our Story Field Carrying Recurrence Recognition Read Medium Compatibility Kind Our Story Nests Inheritance nests within the Our Story Field as the condition through which prior carrying is sustained and passed forward through recognition and recurrence. Reads Inheritance becomes readable where what is received remains identifiable enough to be carried, revised, refused, repaired, or retold. The dependency movement is: First: Bearing and Availability make something carryable beyond the immediate relation. Second: Carrying, Recurrence, Recognition Read, Medium, and Compatibility make inheritance evaluable. Third: Inheritance places that structural read inside the Our Story Field. Carries','Inheritance Inheritance names an our story path read where memory, practice, term, place, obligation, or relation is carried into later participation. Borne and Carried names the human scope…','stable','rooted',0,'third','term','our-story','[]','[]','["second.carrying","second.compatibility","second.kind","second.medium","second.recognition-read","second.recurrence","third.carrying-better","third.our-story","third.our-story-field"]','{"holds":["third.our-story-field","second.carrying","second.recurrence","second.recognition-read","second.medium","second.compatibility","second.kind","third.our-story"],"traces":["third.our-story-field","second.carrying","second.recurrence","second.recognition-read","second.medium","second.compatibility","second.kind","third.our-story"],"carries":[],"pairs":["third.carrying-better"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',227,'sha256:ae8a39daeddaae2233f137ea802acc6989b507ade9fb3a090f8b82270dfa4d43','1970-01-01','2026-06-27');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.inherited-term-drift','Inherited Term Drift','inherited-term-drift','Reality_Mechanics/3_Third/Domains/Language/Applied Reads/Inherited Term Drift.md','https://atlas.realitymechanics.nz/inherited-term-drift.html','# Inherited Term Drift

Inherited Term Drift reads a local case where a received term keeps its name while entering a different structural role.

## Places

Inherited Term Drift places the local case where a received term keeps its name while entering a different structural role.

## Holds

Inherited Term Drift is held by [[Applied Read]], [[Term Drift]], [[Translation]], [[Closure Scope]], [[Language Domain]].

## Pairs

Inherited Term Drift pairs with [[Term Drift]]. Inherited Term Drift names drift carried across translation; Term Drift names drift within a context. Each is a distinct form of term drift.

## Traces

- [[Applied Read]]
- [[Term Drift]]
- [[Translation]]
- [[Closure Scope]]
- [[Language Domain]]

## Nests

Inherited Term Drift nests where this read holds at its field, domain, or practice scope without losing trace.

## Reads

Inherited Term Drift becomes readable where the same term is repeated after its participation has changed.

The dependency movement is:

First: [[Boundary]] and [[Availability]] must hold enough for a term to be re-entered into use.

Second: [[Translation]], [[Recognition Read|Recognition]], and [[Closure Scope]] make the inherited term evaluable as preserved or drifted structural role.

Third: [[Inherited Term Drift]] tests that condition inside the [[Language Domain]] as an applied language read.

Case Movement:

```text
term is inherited
→ term is reused
→ participation changes
→ dependency position must be re-read
```

## Carries

This note carries no further public branch at this scope.','Inherited Term Drift Inherited Term Drift reads a local case where a received term keeps its name while entering a different structural role. Places Inherited Term Drift places the local case where a received term keeps its name while entering a different structural role. Holds Inherited Term Drift is held by Applied Read, Term Drift, Translation, Closure Scope, Language Domain. Pairs Inherited Term Drift pairs with Term Drift. Inherited Term Drift names drift carried across translation; Term Drift names drift within a context. Each is a distinct form of term drift. Traces Applied Read Term Drift Translation Closure Scope Language Domain Nests Inherited Term Drift nests where this read holds at its field, domain, or practice scope without losing trace. Reads Inherited Term Drift becomes readable where the same term is repeated after its participation has changed. The dependency movement is: First: Boundary and Availability must hold enough for a term to be re entered into use. Second: Translation, Recognition Read, and Closure Scope make the inherited term evaluable as preserved or drifted structural role. Third: Inherited Term Drift tests that condition inside the Language Domain as an applied language read. Case Movement: Carries This note carries no further public branch at this scope.','Inherited Term Drift Inherited Term Drift reads a local case where a received term keeps its name while entering a different structural role. Places Inherited Term Drift places the local case…','stable','rooted',0,'third','term','language','[]','[]','["second.closure-scope","third.applied-read","third.language-domain","third.term-drift","third.translation"]','{"holds":["third.applied-read","third.term-drift","third.translation","second.closure-scope","third.language-domain"],"traces":["third.applied-read","third.term-drift","third.translation","second.closure-scope","third.language-domain"],"carries":[],"pairs":["third.term-drift"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',204,'sha256:e6817f3dd422321507bb4c8b45d955af9335de2630c191c87be42be8fc1c5fd3','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.injury','Injury','injury','Reality_Mechanics/3_Third/Fields/Body/Injury.md','https://atlas.realitymechanics.nz/injury.html','# Injury

Injury names embodied damage to available carrying where ordinary movement, pressure, or participation becomes locally incompatible.

## Places

Injury places incompatible carrying within the body at a closure scope — carrying that proceeds against the body''s compatible conditions and damages or removes available bearing.

## Holds

Injury is held by [[Body]], [[Boundary]], [[Carrying]], [[Compatibility]], [[Closure Scope]], [[Harm]], and [[Splinter]]. Carrying must proceed against compatible conditions and a boundary must locate the damage before the condition can be read as injury.

## Pairs

No lateral pair is required at this placement yet; this term currently reads as a branch or terminal read.

## Traces

- [[Body]]
- [[Boundary]]
- [[Carrying]]
- [[Compatibility]]
- [[Closure Scope]]
- [[Harm]]
- [[Splinter]]

## Nests

Injury nests within the Body Field as the condition through which incompatible carrying damages a bodily carrying scope.

## Reads

Injury becomes readable where embodied carrying is damaged enough that continuing as before would increase incompatibility.

The dependency movement is:

First: [[Boundary]] supplies the local embodied limit.

Second: [[Carrying]], [[Compatibility]], and [[Closure Scope]] make damaged participation evaluable.

Third: [[Injury]] places that structural read inside the body branch.

## Carries

Injury carries [[Recovery]]. Recovery names compatible re-bearing following injury — the return of embodied carrying without repeating the incompatibility that caused damage.

- [[Recovery]]','Injury Injury names embodied damage to available carrying where ordinary movement, pressure, or participation becomes locally incompatible. Places Injury places incompatible carrying within the body at a closure scope — carrying that proceeds against the body''s compatible conditions and damages or removes available bearing. Holds Injury is held by Body, Boundary, Carrying, Compatibility, Closure Scope, Harm, and Splinter. Carrying must proceed against compatible conditions and a boundary must locate the damage before the condition can be read as injury. Pairs No lateral pair is required at this placement yet; this term currently reads as a branch or terminal read. Traces Body Boundary Carrying Compatibility Closure Scope Harm Splinter Nests Injury nests within the Body Field as the condition through which incompatible carrying damages a bodily carrying scope. Reads Injury becomes readable where embodied carrying is damaged enough that continuing as before would increase incompatibility. The dependency movement is: First: Boundary supplies the local embodied limit. Second: Carrying, Compatibility, and Closure Scope make damaged participation evaluable. Third: Injury places that structural read inside the body branch. Carries Injury carries Recovery. Recovery names compatible re bearing following injury — the return of embodied carrying without repeating the incompatibility that caused damage. Recovery','Injury Injury names embodied damage to available carrying where ordinary movement, pressure, or participation becomes locally incompatible. Places Injury places incompatible carrying within the…','stable','rooted',0,'third','term','body','[]','[]','["first.boundary","second.carrying","second.closure-scope","second.compatibility","second.splinter","third.body","third.harm","third.recovery"]','{"holds":["third.body","first.boundary","second.carrying","second.compatibility","second.closure-scope","third.harm","second.splinter"],"traces":["third.body","first.boundary","second.carrying","second.compatibility","second.closure-scope","third.harm","second.splinter"],"carries":["third.recovery"],"pairs":[],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',200,'sha256:285c50a32c17a3e6bc9e840ed5c1cbfa08ebf70e3ed5c0d4681ad235460c5b37','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.knowing','Knowing','knowing','Reality_Mechanics/3_Third/Placement Modes/Knowing.md','https://atlas.realitymechanics.nz/knowing.html','# Knowing

Knowing names the placement mode where participation is primarily carried through readable distinction, recognition, test, or retained understanding.

## Places

Knowing places the mode where participation is primarily carried through readable distinction, recognition, test, or retained understanding — where what is read becomes identifiable, checkable, or teachable.

## Holds

Knowing is held by [[Placement Mode]], [[Readability]], [[Recognition Read|Recognition]], and [[Know]]. A mode of participation must exist, readability must produce distinct conditions, recognition must be possible, and the capacity to know must be available before retained understanding can be placed as the primary mode.

## Pairs

Knowing pairs with [[Expressing]]. Knowing is the inward direction — reading in toward distinction and retained understanding; Expressing is the outward direction — making readable form available to others.

## Traces

- [[Placement Mode]]
- [[Readability]]
- [[Recognition Read|Recognition]]
- [[Know]]

## Nests

Knowing nests within Placement Modes as the understanding mode — where the primary movement is readable distinction becoming identifiable, checkable, modelled, or retained.

## Reads

Knowing becomes recognisable where a note is primarily placed by a read becoming identifiable, checkable, retained, modelled, taught, or revised.

## Carries

This note carries no further public branch at this scope.','Knowing Knowing names the placement mode where participation is primarily carried through readable distinction, recognition, test, or retained understanding. Places Knowing places the mode where participation is primarily carried through readable distinction, recognition, test, or retained understanding — where what is read becomes identifiable, checkable, or teachable. Holds Knowing is held by Placement Mode, Readability, Recognition Read, and Know. A mode of participation must exist, readability must produce distinct conditions, recognition must be possible, and the capacity to know must be available before retained understanding can be placed as the primary mode. Pairs Knowing pairs with Expressing. Knowing is the inward direction — reading in toward distinction and retained understanding; Expressing is the outward direction — making readable form available to others. Traces Placement Mode Readability Recognition Read Know Nests Knowing nests within Placement Modes as the understanding mode — where the primary movement is readable distinction becoming identifiable, checkable, modelled, or retained. Reads Knowing becomes recognisable where a note is primarily placed by a read becoming identifiable, checkable, retained, modelled, taught, or revised. Carries This note carries no further public branch at this scope.','Knowing Knowing names the placement mode where participation is primarily carried through readable distinction, recognition, test, or retained understanding. Places Knowing places the mode where…','stable','rooted',0,'third','term','placement-modes','[]','[]','["second.know","second.readability","second.recognition-read","third.expressing","third.placement-mode"]','{"holds":["third.placement-mode","second.readability","second.recognition-read","second.know"],"traces":["third.placement-mode","second.readability","second.recognition-read","second.know"],"carries":[],"pairs":["third.expressing"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',185,'sha256:a9efe6b1affcb179a3e20468f173cf4bdd5d6fec99e04a7380fa55428c2133c1','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.knowledge-field','Knowledge Field','knowledge-field','Reality_Mechanics/3_Third/Fields/Knowledge/Knowledge Field.md','https://atlas.realitymechanics.nz/knowledge-field.html','# Knowledge Field

Knowledge Field names the recurring field of participation through which knowing, modelling, and carrying what has been retraced become readable as organised experience.

## Places

Knowledge Field places a recurring field of participation.

## Holds

Knowledge Field is held by [[Field of Participation]], [[Organic Field]], [[Know]], [[Carrying]], [[Recurrence]], and [[Compatibility]]. [[Knowledge]] nests within this field; it does not hold the field that carries it.

## Pairs

Knowledge Field pairs with [[Faith Field]]. Knowledge Field names the field of carried knowing tested through recurrence and compatibility; Faith Field names the field of carried commitment toward unavailable resolution. Each requires the other to be distinguishable: knowledge tests what faith carries; faith holds what knowledge cannot yet reach.

## Traces

- [[Field of Participation]]
- [[Organic Field]]
- [[Know]]
- [[Carrying]]
- [[Recurrence]]
- [[Compatibility]]

## Nests

Knowledge Field nests as a public field container. Detailed branch notes remain compressed as working material.

[[Bearing Source]]
[[Competence Boundary]]
[[Diagnosis]]
[[Knowledge]]
[[Learning Pace]]
[[Modelling]]
[[Pace Mismatch]]
[[Reality Check]]
[[Teaching]]
[[Teaching Boundary]]

## Reads

Knowledge Field becomes recognisable where knowing, modelling, teaching, revision, inheritance, or retraced understanding organises participation as carried knowledge.

At the [[Translation Boundary]], [[Know]], [[Readability]], [[Retrace Read|Retrace]], [[Check]], [[Modelling]], and [[Bearing Source]] can become terminal to this field as local reads such as [[Knowledge]], [[Competence Boundary]], [[Reality Check]], [[Teaching]], [[Teaching Boundary]], and [[Diagnosis]].

## Carries

This field carries local terminal translations into the branch notes named in Nests.

- [[Knowledge]]
- [[Modelling]]
- [[Experimental Science]]
- [[Teaching]]','Knowledge Field Knowledge Field names the recurring field of participation through which knowing, modelling, and carrying what has been retraced become readable as organised experience. Places Knowledge Field places a recurring field of participation. Holds Knowledge Field is held by Field of Participation, Organic Field, Know, Carrying, Recurrence, and Compatibility. Knowledge nests within this field; it does not hold the field that carries it. Pairs Knowledge Field pairs with Faith Field. Knowledge Field names the field of carried knowing tested through recurrence and compatibility; Faith Field names the field of carried commitment toward unavailable resolution. Each requires the other to be distinguishable: knowledge tests what faith carries; faith holds what knowledge cannot yet reach. Traces Field of Participation Organic Field Know Carrying Recurrence Compatibility Nests Knowledge Field nests as a public field container. Detailed branch notes remain compressed as working material. Bearing Source Competence Boundary Diagnosis Knowledge Learning Pace Modelling Pace Mismatch Reality Check Teaching Teaching Boundary Reads Knowledge Field becomes recognisable where knowing, modelling, teaching, revision, inheritance, or retraced understanding organises participation as carried knowledge. At the Translation Boundary, Know, Readability, Retrace Read, Check, Modelling, and Bearing Source can become terminal to this field as local reads such as Knowledge, Competence Boundary, Reality Check, Teaching, Teaching Boundary, and Diagnosis. Carries This field carries local terminal translations into the branch notes named in Nests. Knowledge Modelling Experimental Science Teaching','Knowledge Field Knowledge Field names the recurring field of participation through which knowing, modelling, and carrying what has been retraced become readable as organised experience. Places…','stable','rooted',0,'third','term','knowledge','[]','[]','["second.carrying","second.compatibility","second.know","second.recurrence","third.experimental-science","third.faith-field","third.field-of-participation","third.knowledge","third.modelling","third.organic-field","third.teaching"]','{"holds":["third.field-of-participation","third.organic-field","second.know","second.carrying","second.recurrence","second.compatibility"],"traces":["third.field-of-participation","third.organic-field","second.know","second.carrying","second.recurrence","second.compatibility"],"carries":["third.knowledge","third.modelling","third.experimental-science","third.teaching"],"pairs":["third.faith-field"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',229,'sha256:fa8447e41358ae44066f50dc56e234498bfa2998deb958f66dcd4ec182c3540e','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.knowledge','Knowledge','knowledge','Reality_Mechanics/3_Third/Fields/Knowledge/Knowledge.md','https://atlas.realitymechanics.nz/knowledge.html','# Knowledge

Knowledge names organised carried knowing that can be retained, tested, taught, revised, inherited, or challenged within a field of participation.

This note places [[Know]] inside the [[Knowledge Field]] as organised carried understanding.

## Places

Knowledge places the third-order field where knowing is maintained, tested, taught, or revised through participatory carrying — the structural field for know, bearing source, modelling, competence, and reality check.

## Holds

Knowledge is held by [[Knowledge Field]], [[Know]], [[Carrying]], [[Recurrence]], [[Compatibility]], [[Medium]], [[Coherence]], and [[World]]. Knowing must be carried, tested against compatibility, and sustained through recurrence before knowledge can be named as a field condition.

## Pairs

Knowledge pairs with [[Reality Check]]: knowledge names the field where knowing is maintained, tested, and revised through participatory carrying; reality check names the evaluative read through which a claim within that field is tested against what actually bears it. Each requires the other — knowledge without reality check becomes unanchored; reality check without knowledge has no field to test within.

## Traces

- [[Knowledge Field]]
- [[Know]]
- [[Carrying]]
- [[Recurrence]]
- [[Compatibility]]
- [[Medium]]
- [[Coherence]]
- [[World]]

## Nests

Knowledge nests within the Knowledge Field branch as the field-level container for all knowledge structural reads.

[[Competence Boundary]]
[[Bearing Source]]
[[Modelling]]
[[Reality Check]]

## Reads

Knowledge becomes readable where knowing is organised enough to be carried beyond the immediate act of knowing while remaining open to test, revision, or transmission.

Knowledge is relative in the structural sense: not arbitrary, but placed through bearing source, competence boundary, closure scope, medium, and the world that can check it.

The dependency movement is:

First: [[Availability]] and [[Boundary]] make a read distinguishable enough to be held.

Second: [[Read]], [[Recognition Read|Recognition]], [[Know]], [[Carrying]], [[Recurrence]], [[Compatibility]], and [[Medium]] make recognised reads retainable and revisable.

Third: [[Knowledge]] places that structural read inside the [[Knowledge Field]].

Distinction:

Know is a recognised read held as available at a closure scope.

Knowledge is organised carried knowing.

Knowing is the participatory root through which knowledge is maintained, tested, taught, or revised.

## Carries

- [[Competence Boundary]]

- [[Modelling]]
- [[Reality Check]]
- [[Teaching]]','Knowledge Knowledge names organised carried knowing that can be retained, tested, taught, revised, inherited, or challenged within a field of participation. This note places Know inside the Knowledge Field as organised carried understanding. Places Knowledge places the third order field where knowing is maintained, tested, taught, or revised through participatory carrying — the structural field for know, bearing source, modelling, competence, and reality check. Holds Knowledge is held by Knowledge Field, Know, Carrying, Recurrence, Compatibility, Medium, Coherence, and World. Knowing must be carried, tested against compatibility, and sustained through recurrence before knowledge can be named as a field condition. Pairs Knowledge pairs with Reality Check: knowledge names the field where knowing is maintained, tested, and revised through participatory carrying; reality check names the evaluative read through which a claim within that field is tested against what actually bears it. Each requires the other — knowledge without reality check becomes unanchored; reality check without knowledge has no field to test within. Traces Knowledge Field Know Carrying Recurrence Compatibility Medium Coherence World Nests Knowledge nests within the Knowledge Field branch as the field level container for all knowledge structural reads. Competence Boundary Bearing Source Modelling Reality Check Reads Knowledge becomes readable where knowing is organised enough to be carried beyond the immediate act of knowing while remaining open to test, revision, or transmission. Knowledge is relative in the structural sense: not arbitrary, but placed through bearing source, competence boundary, closure scope, medium, and the world that can check it. The dependency movement is: First: Availability and Boundary make a read distinguishable enough to be held. Second: Read, Recognition Read, Know, Carrying, Recurrence, Compatibility, and Medium make recognised reads retainable and revisable. Third: Knowledge places that structural read inside the Knowledge Field. Distinction: Know is a recognised read held as available at a closure scope. Knowledge is organised carried knowing. Knowing is the participatory root through which knowledge is maintained, tested, taught, or revised. Carries Competence Boundary Modelling Reality Check Teaching','Knowledge Knowledge names organised carried knowing that can be retained, tested, taught, revised, inherited, or challenged within a field of participation. This note places Know inside the…','stable','rooted',0,'third','term','knowledge','[]','[]','["second.carrying","second.coherence","second.compatibility","second.know","second.medium","second.recurrence","second.world","third.competence-boundary","third.knowledge-field","third.modelling","third.reality-check","third.teaching"]','{"holds":["third.knowledge-field","second.know","second.carrying","second.recurrence","second.compatibility","second.medium","second.coherence","second.world"],"traces":["third.knowledge-field","second.know","second.carrying","second.recurrence","second.compatibility","second.medium","second.coherence","second.world"],"carries":["third.modelling","third.reality-check","third.competence-boundary","third.teaching"],"pairs":["third.reality-check"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',328,'sha256:bb27b2b54e27d5ea912de1515ba91f515bcdaf0266b41ca64bf430b3a837a72d','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.language-domain','Language Domain','language-domain','Reality_Mechanics/3_Third/Domains/Language/Language Domain.md','https://atlas.realitymechanics.nz/language-domain.html','# Language Domain

Language Domain names the organised participation context through which naming, translating, representing, and carrying meaning through terms become readable as shared use.

## Places

Language Domain places the organised participation context through which naming, translating, representing, and carrying meaning through terms become readable as shared use.

## Holds

Language Domain is held by [[Domain]], [[Expression Field]], [[Language Field]], [[Knowledge Field]], and [[Medium]].

## Pairs

No lateral pair is required at this placement yet; this term currently reads as a branch or terminal read.

## Traces

- [[Domain]]
- [[Expression Field]]
- [[Language Field]]
- [[Knowledge Field]]
- [[Medium]]

## Nests

Language Domain nests where this read holds at its field, domain, or practice scope without losing trace.

## Reads

Language Domain becomes recognisable where meaning is intentionally, culturally, or conventionally organised through naming, translation, representation, address, instruction, or term use.

At the [[Translation Boundary]], [[Term]], [[Trace]], [[Medium]], [[Representation]], [[Translation]], and [[Source Drift|drift]] become terminal to this domain as [[Language]], [[Representation]], [[Translation]], [[Term Drift]], and [[Inherited Term Drift]].

## Carries

- [[Language]]
- [[Representation]]
- [[Translation]]
- [[Term Drift]]
- [[Inherited Term Drift]]','Language Domain Language Domain names the organised participation context through which naming, translating, representing, and carrying meaning through terms become readable as shared use. Places Language Domain places the organised participation context through which naming, translating, representing, and carrying meaning through terms become readable as shared use. Holds Language Domain is held by Domain, Expression Field, Language Field, Knowledge Field, and Medium. Pairs No lateral pair is required at this placement yet; this term currently reads as a branch or terminal read. Traces Domain Expression Field Language Field Knowledge Field Medium Nests Language Domain nests where this read holds at its field, domain, or practice scope without losing trace. Reads Language Domain becomes recognisable where meaning is intentionally, culturally, or conventionally organised through naming, translation, representation, address, instruction, or term use. At the Translation Boundary, Term, Trace, Medium, Representation, Translation, and Source Drift become terminal to this domain as Language, Representation, Translation, Term Drift, and Inherited Term Drift. Carries Language Representation Translation Term Drift Inherited Term Drift','Language Domain Language Domain names the organised participation context through which naming, translating, representing, and carrying meaning through terms become readable as shared use. Places…','stable','rooted',0,'third','term','language','[]','[]','["second.medium","third.domain","third.expression-field","third.inherited-term-drift","third.knowledge-field","third.language","third.language-field","third.representation","third.term-drift","third.translation"]','{"holds":["third.domain","third.expression-field","third.language-field","third.knowledge-field","second.medium"],"traces":["third.domain","third.expression-field","third.language-field","third.knowledge-field","second.medium"],"carries":["third.language","third.representation","third.translation","third.term-drift","third.inherited-term-drift"],"pairs":[],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',167,'sha256:5e0f9b63e30d549089375fc070540eecc3da86bbf90439fce009b97e9a0166ff','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.language-field','Language Field','language-field','Reality_Mechanics/3_Third/Fields/Expression/Language Field.md','https://atlas.realitymechanics.nz/language-field.html','# Language Field

A Language Field names a recurring field of participation through which readable difference through medium becomes available. A language field is not defined by a grammar, vocabulary, culture, or encoding system. It becomes available where participation repeatedly organises through the same recurring capacity to name, distinguish, and trace difference through a medium.

Language fields are the organic bed from which language domains, branches, and applied reads grow. A language domain organises one or more language fields into a recognisable practice, vocabulary, or applied structure. The field precedes and grounds the domain.

## Places

Language Field places the recurring field through which readable difference through medium becomes available.

## Holds

Language Field is held by [[Field of Participation]], [[Organic Field]], [[Readability]], [[Difference]], and [[Medium]]. Participation must structure a recurring scope; readability must be available; difference must be present through a medium before the language field can be named.

## Pairs

Language Field pairs with [[Expression Field]]: language field names the field of readable difference through medium — where distinction becomes nameable and traceable; expression field names the field of outward appearance through medium — where relation becomes visibly present through form, gesture, affect, or sound. Each requires the other to be locatable: language is only readable against a background of expression; expression is only outward against a background of what can be named.

## Traces

Language Field traces to [[Field of Participation]], [[Organic Field]], [[Readability]], [[Difference]], and [[Medium]].

- [[Field of Participation]]
- [[Organic Field]]
- [[Readability]]
- [[Difference]]
- [[Medium]]
- [[Readability]]
- [[Difference]]

## Nests

Language Field nests as a public field container within the Expression Field cluster.

## Reads

Language Field becomes recognisable where readable difference through a medium becomes available as a recurring participatory field — where what can be named and traced recurs across cases, domains, and branches.

## Carries

Nothing at field grain. [[Language]], [[Representation]], and [[Translation]] trace to [[Language Domain]]; the field does not carry what the domain grounds.','Language Field A Language Field names a recurring field of participation through which readable difference through medium becomes available. A language field is not defined by a grammar, vocabulary, culture, or encoding system. It becomes available where participation repeatedly organises through the same recurring capacity to name, distinguish, and trace difference through a medium. Language fields are the organic bed from which language domains, branches, and applied reads grow. A language domain organises one or more language fields into a recognisable practice, vocabulary, or applied structure. The field precedes and grounds the domain. Places Language Field places the recurring field through which readable difference through medium becomes available. Holds Language Field is held by Field of Participation, Organic Field, Readability, Difference, and Medium. Participation must structure a recurring scope; readability must be available; difference must be present through a medium before the language field can be named. Pairs Language Field pairs with Expression Field: language field names the field of readable difference through medium — where distinction becomes nameable and traceable; expression field names the field of outward appearance through medium — where relation becomes visibly present through form, gesture, affect, or sound. Each requires the other to be locatable: language is only readable against a background of expression; expression is only outward against a background of what can be named. Traces Language Field traces to Field of Participation, Organic Field, Readability, Difference, and Medium. Field of Participation Organic Field Readability Difference Medium Readability Difference Nests Language Field nests as a public field container within the Expression Field cluster. Reads Language Fi