INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.neglect','Neglect','neglect','Reality_Mechanics/3_Third/Fields/Relational Participation/Bearing Relations/Neglect.md','https://atlas.realitymechanics.nz/neglect.html','# Neglect

Neglect names required bearing not supplied, not entered, or not maintained where availability depends on it.

## Places

Neglect places the failure to hold bearing that preserves availability — the condition where care-bearing becomes absent, insufficient, or discontinued.

## Holds

Neglect is held by [[Care]], [[Bearing]], and [[Availability]]. Care must be the relevant condition and availability must be at stake before bearing''s absence or insufficiency can be named as neglect.

## Pairs

Neglect pairs with [[Care]]. Care names bearing that preserves availability through relation; Neglect names the failure to hold that bearing.

## Traces

- [[Care]]
- [[Bearing]]
- [[Availability]]

## Nests

Neglect nests within Relational Participation as the condition where care-bearing fails to hold — the structural ground for repair, harm, and care-without-bearing reads.

## Reads

Neglect becomes readable where availability requires bearing and the required bearing is not supplied at the relevant closure scope.

## Carries

- [[Repair]]

The dependency movement is:

First: [[Availability]] requires [[Bearing]] to remain holdable.

Second: carrying fails because required bearing is not supplied or maintained.

Third: [[Neglect]] places that absence inside bearing relations.','Neglect Neglect names required bearing not supplied, not entered, or not maintained where availability depends on it. Places Neglect places the failure to hold bearing that preserves availability — the condition where care bearing becomes absent, insufficient, or discontinued. Holds Neglect is held by Care, Bearing, and Availability. Care must be the relevant condition and availability must be at stake before bearing''s absence or insufficiency can be named as neglect. Pairs Neglect pairs with Care. Care names bearing that preserves availability through relation; Neglect names the failure to hold that bearing. Traces Care Bearing Availability Nests Neglect nests within Relational Participation as the condition where care bearing fails to hold — the structural ground for repair, harm, and care without bearing reads. Reads Neglect becomes readable where availability requires bearing and the required bearing is not supplied at the relevant closure scope. Carries Repair The dependency movement is: First: Availability requires Bearing to remain holdable. Second: carrying fails because required bearing is not supplied or maintained. Third: Neglect places that absence inside bearing relations.','Neglect Neglect names required bearing not supplied, not entered, or not maintained where availability depends on it. Places Neglect places the failure to hold bearing that preserves availability…','stable','rooted',0,'third','term','relational-participation','[]','[]','["first.availability","first.bearing","third.care","third.repair"]','{"holds":["third.care","first.bearing","first.availability"],"traces":["third.care","first.bearing","first.availability"],"carries":["third.repair"],"pairs":["third.care"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',174,'sha256:9c69173dc42b0188446fff6473cb1c35b7fb7d98af268d6132e0f061a65c972c','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.nested-coupling','Nested Coupling','nested-coupling','Reality_Mechanics/3_Third/Fields/Relational Participation/Bearing Relations/Nested Coupling.md','https://atlas.realitymechanics.nz/nested-coupling.html','# Nested Coupling

Nested coupling names Coupling that becomes available as participation in further coupling.

## Places

Nested Coupling places coupling held within a larger coupling structure — distinct resolved conditions in mutual availability where that availability is itself carried within a containing relation.

## Holds

Nested Coupling is held by [[Coupling]], [[Nested Relation]], and [[Carrying]]. Coupling must be present, the nested relation must carry it, and carrying must continue before the nesting of coupling can be read.

## Pairs

Nested Coupling pairs with [[Engineered Coupling]]: nested coupling names coupling held within a larger coupling structure — mutual availability that is itself carried within a containing relation; engineered coupling names coupling deliberately constructed to hold conditions in compatible mutual availability through constraint. Each requires the other to be locatable — nested coupling is only readable against the possibility of engineered coupling; engineered coupling is only readable against the possibility of coupling arising through nesting.

## Traces

- [[Coupling]]
- [[Nested Relation]]
- [[Carrying]]

## Nests

Nested Coupling nests within Relational Participation as the condition through which coupling is carried within a wider carrying scope — the structural ground for family, organisation, and embedded social structure reads.

## Reads

Nested Coupling becomes readable where coupling participates in further coupling without losing its dependency order.

The dependency movement is:

First: [[Bearing]] and [[Resolution]] make coupling possible.

Second: [[Coupling]], [[Nested Relation]], [[Participation]], and [[Carrying]] make further relation evaluable.

Third: [[Nested Coupling]] places that structural read inside bearing relations.

## Carries

This note carries no further public branch at this scope.','Nested Coupling Nested coupling names Coupling that becomes available as participation in further coupling. Places Nested Coupling places coupling held within a larger coupling structure — distinct resolved conditions in mutual availability where that availability is itself carried within a containing relation. Holds Nested Coupling is held by Coupling, Nested Relation, and Carrying. Coupling must be present, the nested relation must carry it, and carrying must continue before the nesting of coupling can be read. Pairs Nested Coupling pairs with Engineered Coupling: nested coupling names coupling held within a larger coupling structure — mutual availability that is itself carried within a containing relation; engineered coupling names coupling deliberately constructed to hold conditions in compatible mutual availability through constraint. Each requires the other to be locatable — nested coupling is only readable against the possibility of engineered coupling; engineered coupling is only readable against the possibility of coupling arising through nesting. Traces Coupling Nested Relation Carrying Nests Nested Coupling nests within Relational Participation as the condition through which coupling is carried within a wider carrying scope — the structural ground for family, organisation, and embedded social structure reads. Reads Nested Coupling becomes readable where coupling participates in further coupling without losing its dependency order. The dependency movement is: First: Bearing and Resolution make coupling possible. Second: Coupling, Nested Relation, Participation, and Carrying make further relation evaluable. Third: Nested Coupling places that structural read inside bearing relations. Carries This note carries no further public branch at this scope.','Nested Coupling Nested coupling names Coupling that becomes available as participation in further coupling. Places Nested Coupling places coupling held within a larger coupling structure —…','stable','rooted',0,'third','term','relational-participation','[]','[]','["second.carrying","second.coupling","second.nested-relation","third.engineered-coupling"]','{"holds":["second.coupling","second.nested-relation","second.carrying"],"traces":["second.coupling","second.nested-relation","second.carrying"],"carries":[],"pairs":["third.engineered-coupling"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',246,'sha256:aee30edce4fd49e28def090445e4e886091fcc5021d6ee1a380fe302076b9ab5','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.nesting','Nesting','nesting','Reality_Mechanics/3_Third/Nesting.md','https://atlas.realitymechanics.nz/nesting.html','# Nesting

Nesting names ordered participation: prior organisation remaining available within later organisation.

Nesting carries; modelling represents.

A prior read, trace, or organisation becomes nested where it continues to participate inside a later read without needing to be separately reconstructed.

Nested relation orders. Coupling makes relation connected enough to participate; nesting keeps that participation dependency-ordered enough to remain retraceable. Connection without nesting becomes flat; nesting without coupling becomes detached.

Nesting is what makes a term''s position within the dependency order determinable. Without nesting, carry and trace give direction but not depth — a term can be followed forward or backward, but where it sits in the order can only be asserted, not located. Where nesting holds, running carry and trace simultaneously through the same passage resolves position: the nested structure is what the carry-trace test is actually measuring. This is the structural warrant for nesting — not only that it keeps participation retraceable, but that it makes the order locatable at all.

## Places

Nesting places ordered participation — prior organisation remaining available within later organisation.

## Holds

Nesting is held by [[Participation]], [[Recurrence]], and [[Field of Participation]]. Participation must recur in a field before prior organisation can remain available within later organisation.

## Pairs

Participation, Recurrence, and Field of Participation carry downward into Nesting. Nesting is vertical rather than lateral. Its structural contrast is flat participation, where connection continues without prior order remaining retraceable.

## Traces

- [[Participation]]
- [[Recurrence]]
- [[Field of Participation]]
## Nests

Nesting nests where prior organisation remains available within later organisation without being replaced.

## Reads

Nesting becomes recognisable where later participation carries prior organisation within it, ordering relation by dependency rather than flattening it into connection alone.

The prior path is not repeated as a copy. It remains available within the new participation as a carried structure.

**Construction read.** A beam is supported by a foundation. Tracing back from the beam and carrying forward from the foundation do not arrive at each other directly — they meet at a stud or fixing nested between them. The nested term is where both directions resolve. From the beam alone, the support is present but how it is held is not fully readable. From the foundation alone, the load path is present but its terminus is not. Running both directions simultaneously locates the stud — the nesting position — and makes its bearing readable: what it is holding, what presses on it, what it must withstand. Constraint is one form that bearing takes when readable as a limit, but it is downstream of the bearing the nesting reveals, not the nesting itself. Once the wall is clad, the fixing becomes invisible; the load still carries, the beam still holds, but the bearing at the nested term is no longer directly readable. The nesting remains structurally present and recoverable by the carry-trace test — but it has become hidden bearing.

## Carries

- [[Recursion]]
- [[Third Order Crossing]]
- [[Legion]]
- [[Higher Order]]

## Order-Terminal

Nesting is order-terminal for Third Order. It completes the readable length of third-order participation by carrying prior organisation inside later organisation. What continues is participation with prior order retained within it.','Nesting Nesting names ordered participation: prior organisation remaining available within later organisation. Nesting carries; modelling represents. A prior read, trace, or organisation becomes nested where it continues to participate inside a later read without needing to be separately reconstructed. Nested relation orders. Coupling makes relation connected enough to participate; nesting keeps that participation dependency ordered enough to remain retraceable. Connection without nesting becomes flat; nesting without coupling becomes detached. Nesting is what makes a term''s position within the dependency order determinable. Without nesting, carry and trace give direction but not depth — a term can be followed forward or backward, but where it sits in the order can only be asserted, not located. Where nesting holds, running carry and trace simultaneously through the same passage resolves position: the nested structure is what the carry trace test is actually measuring. This is the structural warrant for nesting — not only that it keeps participation retraceable, but that it makes the order locatable at all. Places Nesting places ordered participation — prior organisation remaining available within later organisation. Holds Nesting is held by Participation, Recurrence, and Field of Participation. Participation must recur in a field before prior organisation can remain available within later organisation. Pairs Participation, Recurrence, and Field of Participation carry downward into Nesting. Nesting is vertical rather than lateral. Its structural contrast is flat participation, where connection continues without prior order remaining retraceable. Traces Participation Recurrence Field of Participation Nests Nesting nests where prior organisation remains available within later organisation without being replaced. Reads Nesting becomes recognisable where later participation carries prior organisation within it, ordering relation by dependency rather than flattening it into connection alone. The prior path is not repeated as a copy. It remains available within the new participation as a carried structure. Construction read. A beam is supported by a foundation. Tracing back from the beam and carrying forward from the foundation do not arrive at each other directly — they meet at a stud or fixing nested between them. The nested term is where both directions resolve. From the beam alone, the support is present but how it is held is not fully readable. From the foundation alone, the load path is present but its terminus is not. Running both directions simultaneously locates the stud — the nesting position — and makes its bearing readable: what it is holding, what presses on it, what it must withstand. Constraint is one form that bearing takes when readable as a limit, but it is downstream of the bearing the nesting reveals, not the nesting itself. Once the wall is clad, the fixing becomes invisible; the load still carries, the beam still holds, but the bearing at the nested term is no longer directly readable. The nesting remains structurally present and recoverable by the carry trace test — but it has become hidden bearing. Carries Recursion Third Order Crossing Legion Higher Order Order Terminal Nesting is order terminal for Third Order. It completes the readable length of third order participation by carrying prior organisation inside later organisation. What continues is participation with prior order retained within it.','Nesting Nesting names ordered participation: prior organisation remaining available within later organisation. Nesting carries; modelling represents.','stable','rooted',0,'third','term',NULL,'[]','[]','["higher.higher-order","higher.legion","higher.recursion","second.participation","second.recurrence","third.field-of-participation","third.third-order-crossing"]','{"holds":["second.participation","second.recurrence","third.field-of-participation"],"traces":["second.participation","second.recurrence","third.field-of-participation"],"carries":["higher.recursion","third.third-order-crossing","higher.legion","higher.higher-order"],"pairs":[],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"},{"depth":2,"text":"Order-Terminal","anchor":"order-terminal"}]',519,'sha256:021772ba119cc97b24801e4a1ec8699d9f305655bf562e04ec69eeebed60775c','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.neutrino','Neutrino','neutrino','Reality_Mechanics/3_Third/Fields/Natural World/Neutrino.md','https://atlas.realitymechanics.nz/neutrino.html','# Neutrino

Neutrino names a natural-world field condition where traversal remains highly available while ordinary interaction, capture, and direct visibility remain scarce. This note places the neutrino as a third-order physical-field read without making it source structure.

## Places

Neutrino places the physical field condition through which a traversal proceeds with minimal coupling — field participation that passes through medium with scarce interaction.

## Holds

Neutrino is held by [[Physical Field Conditions]], [[Field Availability Pattern]], [[Traversal]], [[Medium]], and [[Coupling]]. Field conditions must hold and traversal must be readable before minimal-coupling field participation can be named.

## Pairs

Neutrino pairs with [[Light]]. Neutrino names minimal-coupling field traversal; Light names full-coupling electromagnetic traversal. Each carries through the physical field under different coupling conditions.

## Traces

- [[Physical Field Conditions]]
- [[Field Availability Pattern]]
- [[Traversal]]
- [[Medium]]
- [[Coupling]]

## Nests

Neutrino nests within Physical Field Conditions as the minimal-coupling traversal condition — where field participation passes through medium without requiring readable coupling.

## Reads

Neutrino becomes readable where a traversing physical condition passes through medium while only rarely becoming available to local detection.

The dependency movement is:

First: [[Availability]] distinguishes traversal from local detection.

Second: [[Traversal]], [[Medium]], [[Visibility]], and [[Coupling]] make rare interaction evaluable.

Third: [[Neutrino]] places that structural read inside natural-world physical-field conditions.

Case Movement:

```text
field condition traverses medium
-> ordinary interaction remains scarce
-> visibility depends on rare coupling
-> indirect detection makes the traversal readable
```

## Carries

This note carries no further public branch at this scope.','Neutrino Neutrino names a natural world field condition where traversal remains highly available while ordinary interaction, capture, and direct visibility remain scarce. This note places the neutrino as a third order physical field read without making it source structure. Places Neutrino places the physical field condition through which a traversal proceeds with minimal coupling — field participation that passes through medium with scarce interaction. Holds Neutrino is held by Physical Field Conditions, Field Availability Pattern, Traversal, Medium, and Coupling. Field conditions must hold and traversal must be readable before minimal coupling field participation can be named. Pairs Neutrino pairs with Light. Neutrino names minimal coupling field traversal; Light names full coupling electromagnetic traversal. Each carries through the physical field under different coupling conditions. Traces Physical Field Conditions Field Availability Pattern Traversal Medium Coupling Nests Neutrino nests within Physical Field Conditions as the minimal coupling traversal condition — where field participation passes through medium without requiring readable coupling. Reads Neutrino becomes readable where a traversing physical condition passes through medium while only rarely becoming available to local detection. The dependency movement is: First: Availability distinguishes traversal from local detection. Second: Traversal, Medium, Visibility, and Coupling make rare interaction evaluable. Third: Neutrino places that structural read inside natural world physical field conditions. Case Movement: Carries This note carries no further public branch at this scope.','Neutrino Neutrino names a natural world field condition where traversal remains highly available while ordinary interaction, capture, and direct visibility remain scarce. This note places the…','stable','rooted',0,'third','term','natural-world','[]','[]','["second.coupling","second.medium","second.traversal","third.field-availability-pattern","third.light","third.physical-field-conditions"]','{"holds":["third.physical-field-conditions","third.field-availability-pattern","second.traversal","second.medium","second.coupling"],"traces":["third.physical-field-conditions","third.field-availability-pattern","second.traversal","second.medium","second.coupling"],"carries":[],"pairs":["third.light"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',223,'sha256:d9f5499f1fad56874fa18472cbda8e353a42b546ba6ffa84d1247441f931950a','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.noise','Noise','noise','Reality_Mechanics/3_Third/Domains/Music/Noise.md','https://atlas.realitymechanics.nz/noise.html','# Noise

Noise names sound not currently readable as signal, pattern, relation, or line at the relevant scope.

Noise is not bad sound. It may be meaningful at another scope, with another instrument, in another domain, or for another participant. It is noise where audible carrying is present but cannot currently be read as signal, pattern, relation, melody, harmony, or rhythm.

## Places

Noise places sound not currently readable as signal, pattern, relation, or line at the relevant scope.

## Holds

Noise is held by [[Sound]], [[Readability]], and [[Scope]]. Sound must be present, and a scope of reading must be active, before unreadable audible carrying can be named as noise.

## Pairs

Noise pairs with [[Sound]]. Sound names audible carrying that can become available to read; Noise names sound whose relation is not currently readable at the relevant scope.

## Traces

- [[Sound]]
- [[Readability]]
- [[Scope]]

## Nests

Noise nests within the music domain as the sound/readability boundary where audible carrying is present but not currently readable as signal, pattern, relation, or line.

## Reads

Noise becomes readable where sound is present but cannot be carried as signal, pattern, relation, melody, harmony, or rhythm at the current scope or resolution band.

## Carries

Noise carries no further public branch at this scope.','Noise Noise names sound not currently readable as signal, pattern, relation, or line at the relevant scope. Noise is not bad sound. It may be meaningful at another scope, with another instrument, in another domain, or for another participant. It is noise where audible carrying is present but cannot currently be read as signal, pattern, relation, melody, harmony, or rhythm. Places Noise places sound not currently readable as signal, pattern, relation, or line at the relevant scope. Holds Noise is held by Sound, Readability, and Scope. Sound must be present, and a scope of reading must be active, before unreadable audible carrying can be named as noise. Pairs Noise pairs with Sound. Sound names audible carrying that can become available to read; Noise names sound whose relation is not currently readable at the relevant scope. Traces Sound Readability Scope Nests Noise nests within the music domain as the sound/readability boundary where audible carrying is present but not currently readable as signal, pattern, relation, or line. Reads Noise becomes readable where sound is present but cannot be carried as signal, pattern, relation, melody, harmony, or rhythm at the current scope or resolution band. Carries Noise carries no further public branch at this scope.','Noise Noise names sound not currently readable as signal, pattern, relation, or line at the relevant scope. Noise is not bad sound.','stable','rooted',0,'third','term','music','[]','[]','["second.readability","second.scope","third.sound"]','{"holds":["third.sound","second.readability","second.scope"],"traces":["third.sound","second.readability","second.scope"],"carries":[],"pairs":["third.sound"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"tex