INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.parenting-boundary','Parenting Boundary','parenting-boundary','Reality_Mechanics/3_Third/Domains/Parenting/Applied Reads/Parenting Boundary.md','https://atlas.realitymechanics.nz/parenting-boundary.html','# Parenting Boundary

Parenting Boundary reads a local case where parental care must locate a boundary that preserves availability without forcing dependence.

## Places

Parenting Boundary places the local case where parental care must locate a boundary that preserves availability without forcing dependence.

## Holds

Parenting Boundary is held by [[Applied Read]], [[Parenting]], [[Boundary]], [[Care]], [[Closure Scope]].

## Pairs

No lateral pair is required at this placement yet; this term currently reads as a branch or terminal read.

## Traces

- [[Applied Read]]
- [[Parenting]]
- [[Boundary]]
- [[Care]]
- [[Closure Scope]]

## Nests

Parenting Boundary nests where this read holds at its field, domain, or practice scope without losing trace.

## Reads

Parenting Boundary becomes readable where a limit preserves the child''s available bearing rather than merely asserting parental direction.

The dependency movement is:

First: [[Boundary]], [[Availability]], and [[Bearing]] must hold enough for dependent relation to remain supportable.

Second: [[Care]], [[Compatibility]], and [[Closure Scope]] make the boundary evaluable as support or forced control.

Third: [[Parenting Boundary]] tests that condition inside the [[Relational Participation Field]] as an applied parenting read.

Case Movement:

```text
dependent availability needs bearing
-> boundary is set
-> care must remain available
-> boundary either supports bearing or becomes forced control
```

## Carries

This note carries no further public branch at this scope.','Parenting Boundary Parenting Boundary reads a local case where parental care must locate a boundary that preserves availability without forcing dependence. Places Parenting Boundary places the local case where parental care must locate a boundary that preserves availability without forcing dependence. Holds Parenting Boundary is held by Applied Read, Parenting, Boundary, Care, Closure Scope. Pairs No lateral pair is required at this placement yet; this term currently reads as a branch or terminal read. Traces Applied Read Parenting Boundary Care Closure Scope Nests Parenting Boundary nests where this read holds at its field, domain, or practice scope without losing trace. Reads Parenting Boundary becomes readable where a limit preserves the child''s available bearing rather than merely asserting parental direction. The dependency movement is: First: Boundary, Availability, and Bearing must hold enough for dependent relation to remain supportable. Second: Care, Compatibility, and Closure Scope make the boundary evaluable as support or forced control. Third: Parenting Boundary tests that condition inside the Relational Participation Field as an applied parenting read. Case Movement: Carries This note carries no further public branch at this scope.','Parenting Boundary Parenting Boundary reads a local case where parental care must locate a boundary that preserves availability without forcing dependence. Places Parenting Boundary places the…','stable','rooted',0,'third','term','parenting','[]','[]','["first.boundary","second.closure-scope","third.applied-read","third.care","third.parenting"]','{"holds":["third.applied-read","third.parenting","first.boundary","third.care","second.closure-scope"],"traces":["third.applied-read","third.parenting","first.boundary","third.care","second.closure-scope"],"carries":[],"pairs":[],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"text":"Traces","anchor":"traces"},{"depth":2,"text":"Nests","anchor":"nests"},{"depth":2,"text":"Reads","anchor":"reads"},{"depth":2,"text":"Carries","anchor":"carries"}]',181,'sha256:c1654ec1e2539108911ad8b1e0a7579947d2618839de6a44c437ec447a7e9ef4','1970-01-01','2026-06-25');
INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.parenting-repair','Parenting Repair','parenting-repair','Reality_Mechanics/3_Third/Domains/Parenting/Applied Reads/Parenting Repair.md','https://atlas.realitymechanics.nz/parenting-repair.html','# Parenting Repair

Parenting Repair reads a local case where parental relation must restore bearing after harm, neglect, rupture, or misrepair.

## Places

Parenting Repair places the local case where parental relation must restore bearing after harm, neglect, rupture, or misrepair.

## Holds

Parenting Repair is held by [[Applied Read]], [[Parenting]], [[Repair]], [[Harm]], [[Neglect]], [[Closure Scope]].

## Pairs

No lateral pair is required at this placement yet; this term currently reads as a branch or terminal read.

## Traces

- [[Applied Read]]
- [[Parenting]]
- [[Repair]]
- [[Harm]]
- [[Neglect]]
- [[Closure Scope]]

## Nests

Parenting Repair nests where this read holds at its field, domain, or practice scope without losing trace.

## Reads

Parenting Repair becomes readable where damaged or absent bearing is re-entered into compatible relation at the evaluated scope.

The dependency movement is:

First: [[Bearing]] must be restored where harm or neglect has interrupted availability.

Second: [[Repair]], [[Compatibility]], and [[Closure Scope]] make parenting repair evaluable as re-bearing or misrepair.

Third: [[Parenting Repair]] tests that condition inside the [[Relational Participation Field]] as an applied parenting read.

Case Movement:

```text
bearing is damaged or absent
-> parental relation resumes
-> repair must restore availability
-> proceeding without re-bearing risks misrepair
```

## Carries

