INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.path-reads','Path Reads','path-reads','Reality_Mechanics/3_Third/Path Reads/Path Reads.md','https://atlas.realitymechanics.nz/path-reads.html','# Path Reads

Path Reads name reusable reads that become available by following a dependency path.

In Third Order, a path read often follows a branch through a [[Translation Boundary|translation joint]]: source term, terminal point, local domain term, applied read.

## Places

Path Reads places reusable reads that become available by following a dependency path.

## Holds

Path Reads is held by [[Branch]] and [[Readability]].

## Pairs

No lateral pair is required at this placement yet; this term currently reads as a branch or terminal read.

## Traces

- [[Branch]]
- [[Readability]]
- [[Domain]]
- [[Terminal]]
- [[Translation Boundary]]

## Nests

Path Reads nests as reusable reads made available by branches through fields or domains.

They can nest the movement from structural term into terminal domain expression, then into local application.

[[Applied Read]]
[[Enchantment]]
[[Resolution Polarity]]

## Reads

Path Reads become recognisable where following a dependency path through a field, domain, or their crossing makes a downstream condition readable.

They help show whether a dense cluster is actually a branch: the read should reveal what carries forward, where it changes language, and how it remains retraceable.
## Carries

- [[Applied Read]]
- [[Degeneration Read]]','Path Reads Path Reads name reusable reads that become available by following a dependency path. In Third Order, a path read often follows a branch through a Translation Boundary: source term, terminal point, local domain term, applied read. Places Path Reads places reusable reads that become available by following a dependency path. Holds Path Reads is held by Branch and Readability. Pairs No lateral pair is required at this placement yet; this term currently reads as a branch or terminal read. Traces Branch Readability Domain Terminal Translation Boundary Nests Path Reads nests as reusable reads made available by branches through fields or domains. They can nest the movement from structural term into terminal domain expression, then into local application. Applied Read Enchantment Resolution Polarity Reads Path Reads become recognisable where following a dependency path through a field, domain, or their crossing makes a downstream condition readable. They help show whether a dense cluster is actually a branch: the read should reveal what carries forward, where it changes language, and how it remains retraceable. Carries Applied Read Degeneration Read','Path Reads Path Reads name reusable reads that become available by following a dependency path. In Third Order, a path read often follows a branch through a Translation Boundary: source term,…','stable','rooted',0,'third','class','path-reads','[]','[]','["second.readability","second.terminal","third.applied-read","third.branch","third.degeneration-read","third.domain","third.translation-boundary"]','{"holds":["third.branch","second.readability"],"traces":["third.branch","second.readability","third.domain","second.terminal","third.translation-boundary"],"carries":["third.applied-read","third.degeneration-read"],"pairs":[],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anchor":"holds"},{"depth":2,"text":"Pairs","anchor":"pairs"},{"depth":2,"t