INSERT OR REPLACE INTO entries (id,title,slug,source_path,public_url,content,plain_text,excerpt,status,garden_status,grounded,entry_order,entry_type,branch,aliases,tags,related,structure,headings,word_count,content_hash,created,updated) VALUES ('third.reciprocity-breakdown','Reciprocity Breakdown','reciprocity-breakdown','Reality_Mechanics/3_Third/Fields/Relational Participation/Bearing Relations/Applied Reads/Reciprocity Breakdown.md','https://atlas.realitymechanics.nz/reciprocity-breakdown.html','# Reciprocity Breakdown

Reciprocity Breakdown reads a local case where mutual participation no longer remains compatibly borne.

## Places

Reciprocity Breakdown places the applied read where reciprocal bearing within participation fails at a closure scope — where bearing no longer moves compatibly between participants.

## Holds

Reciprocity Breakdown is held by [[Applied Read]], [[Reciprocity]], and [[Closure Scope]].

## Pairs

Reciprocity Breakdown pairs with [[Reciprocity]]. Reciprocity names compatible bearing across participation; Reciprocity Breakdown names its failure at scope.

## Traces

- [[Applied Read]]
- [[Reciprocity]]
- [[Closure Scope]]

## Nests

Reciprocity Breakdown nests within Relational Participation as an applied read of Reciprocity at the point of failure.

## Reads

Reciprocity Breakdown becomes readable where one side of participation continues without the mutual bearing required for reciprocal carrying.

The dependency movement is:

First: [[Bearing]] must hold enough for mutual participation to remain supportable.

Second: [[Participation]], [[Compatibility]], and [[Closure Scope]] make reciprocity evaluable as mutually carried or broken.

Third: [[Reciprocity Breakdown]] tests that condition inside the [[Relational Participation Field]] as an applied relation read.

Case Movement:

```text
participation is mutual
-> carrying becomes uneven
-> one side continues without reciprocal bearing
-> reciprocity breaks down
```

## Carries

This note carries no further public branch at this scope.','Reciprocity Breakdown Reciprocity Breakdown reads a local case where mutual participation no longer remains compatibly borne. Places Reciprocity Breakdown places the applied read where reciprocal bearing within participation fails at a closure scope — where bearing no longer moves compatibly between participants. Holds Reciprocity Breakdown is held by Applied Read, Reciprocity, and Closure Scope. Pairs Reciprocity Breakdown pairs with Reciprocity. Reciprocity names compatible bearing across participation; Reciprocity Breakdown names its failure at scope. Traces Applied Read Reciprocity Closure Scope Nests Reciprocity Breakdown nests within Relational Participation as an applied read of Reciprocity at the point of failure. Reads Reciprocity Breakdown becomes readable where one side of participation continues without the mutual bearing required for reciprocal carrying. The dependency movement is: First: Bearing must hold enough for mutual participation to remain supportable. Second: Participation, Compatibility, and Closure Scope make reciprocity evaluable as mutually carried or broken. Third: Reciprocity Breakdown tests that condition inside the Relational Participation Field as an applied relation read. Case Movement: Carries This note carries no further public branch at this scope.','Reciprocity Breakdown Reciprocity Breakdown reads a local case where mutual participation no longer remains compatibly borne. Places Reciprocity Breakdown places the applied read where reciprocal…','stable','rooted',0,'third','term','relational-participation','[]','[]','["second.closure-scope","third.applied-read","third.reciprocity"]','{"holds":["third.applied-read","third.reciprocity","second.closure-scope"],"traces":["third.applied-read","third.reciprocity","second.closure-scope"],"carries":[],"pairs":["third.reciprocity"],"nests":[],"reads":[]}','[{"depth":2,"text":"Places","anchor":"places"},{"depth":2,"text":"Holds","anc